trait AppendBar {
    fn append_bar(self) -> Self;
}

impl AppendBar for Vec<String> {
    fn append_bar(mut self) -> Self {
        self.push(String::from("Bar"));
        self
    }
}

fn main() {
    let foo = vec![String::from("Foo")].append_bar();
    assert_eq!(foo, vec![String::from("Foo"), String::from("Bar")]);
    println!("{:?}", foo);
}
